time_lapse_gcode:
;======== X2D timelapse gcode ========
;======== 2026/05/08 ========
; SKIPPABLE_START
; SKIPTYPE: timelapse
M622.1 S1 ; for prev firware, default turned on

M1002 judge_flag timelapse_record_flag

M622 J1
    {if !spiral_mode && !(has_timelapse_safe_pos) }
        {if most_used_physical_extruder_id!= curr_physical_extruder_id || timelapse_type == 1}
            M83
            G1 Z{max_layer_z + 0.4} F1200
            M400
        {endif}
    {endif}

    {if has_timelapse_safe_pos && !spiral_mode}
        M9711 M{timelapse_type} E{most_used_physical_extruder_id} U{timelapse_pos_x} V{timelapse_pos_y} Z{layer_z + 0.4} S11 C10 O0 T3000
    {else}
        {if spiral_mode}
            M971 S11 C10 O0
            M1004 S5 P1  ; external shutter
        {else}
            M9711 M{timelapse_type} E{most_used_physical_extruder_id} Z{layer_z + 0.4} S11 C10 O0 T3000
        {endif}
    {endif}

    {if !spiral_mode && !(has_timelapse_safe_pos) }
        {if most_used_physical_extruder_id!= curr_physical_extruder_id || timelapse_type == 1}
            G90
            G1 Z{max_layer_z + 3.0} F1200
            G91
            G0 Y-20 F18000
            G90
            M83
        {endif}
    {endif}
M623
; SKIPPABLE_END
